"""
This module provides a ``GeoAnnotations`` class to provide tools to handle a large number of
detections / annotations (as a list of ``DetectionBox``).
It is very useful to load and save annotations in different formats:
- DXF / DWG through the use of ``ezdxf.document.Drawing`` object
- Shapefile or GeoJson through the use of ``gpd.GeoDataFrame``
- Pascal Voc format architecture with its xml annotation through the use of ``PascalVocXml``
"""

import logging
from typing import List, Optional, Dict, Tuple, Callable, Sequence

import ezdxf.document
import geopandas as gpd
import numpy as np
import numpy.typing as npt
import pandas as pd
from shapely.geometry import Polygon, Point
from shapely.geometry.base import BaseGeometry
from shapely.affinity import rotate
from typing_extensions import Self

from geosat.geo_annotations.transformers import (
    convert_2d_coords_to_oriented_detection_box,
)
from geosat.tools.annotation import PascalVocXml, PascalVocObject, AnnotationSize
from geosat.tools.boundingboxes import (
    DetectionBox,
    normalize_angle_and_shape,
    OrientedDetectionBox,
    Number,
    BoundingBox,
)


class GeoAnnotations:
    """
    Basic class containing ground object information.
    """

    def __init__(self, detection_boxes: Sequence[DetectionBox]) -> None:
        self.detection_boxes: List[OrientedDetectionBox] = [
            (
                box
                if isinstance(box, OrientedDetectionBox)
                else OrientedDetectionBox.from_detection_box(box, angle=0.0)
            )
            for box in detection_boxes
        ]

    @classmethod
    def merge(cls, objects_list: List[Self]) -> Self:
        objs = []
        for obj in objects_list:
            objs.extend(obj.detection_boxes)
        return cls(objs)

    @classmethod
    def from_pascalvoc(cls, pascalvoc: PascalVocXml) -> Self:
        odb = [obj.to_detection_box() for obj in pascalvoc.objects]
        return cls(odb)

    @classmethod
    def from_dxf(
        cls,
        doc: ezdxf.document.Drawing,
        mapping: Dict[Tuple[str, str], str],
        offsets: Optional[Dict[str, Tuple[float, float]]] = None,
    ) -> Self:
        # sourcery skip: use-fstring-for-concatenation
        """
        :param doc: An ezdxf drawing containing layers and blocks from `mapping` to be extracted.
        :param mapping: A dictionary linking a layer and his blocks to a given class name. A '*' can
            be used instead of a specific block name to denote that we want to include all blocks from
            the specified layer. In this case, that should be the only occurrence of this layer name.
            Keep in mind that we only considers AutoCad Blocks here (DXF 'Insert' objects).
        :param offsets: A dictionary associating a block names to the offset of insertion point within the block layout.
            This offset is the translation that should be applied to the insertion point in the block layout to be at
            the middle of the object.
            Indeed, a block can be placed with its insertion point at the corner of a rectangular shaped object.
            Block names should be in lowercase.
        """
        offsets_keys_lower = (
            {k.lower(): v for k, v in offsets.items()} if offsets else {}
        )
        detection_boxes = []
        msp = doc.modelspace()
        for (layer_name, block_name), class_name in mapping.items():
            block_query = (
                f" & name=='{block_name}'" if block_name not in ["*", "", ".*"] else ""
            )
            query = f"INSERT[layer ? '{layer_name}'" + block_query + "]"
            blocks = msp.query(query)
            for block in blocks:
                block_name = block.dxf.name.lower()
                dx, dy = offsets_keys_lower.get(block_name, (0, 0))
                insertion_pt = block.dxf.insert.x, block.dxf.insert.y
                rot = block.dxf.rotation  # ezdxf rotations are within [0 ; 360[ degrees
                shape = block.dxf.xscale, block.dxf.yscale
                center = rotate(
                    Point(
                        insertion_pt[0] + dx * shape[0], insertion_pt[1] + dy * shape[1]
                    ),
                    rot,
                    Point(insertion_pt),
                ).coords[0]
                normalized_rot, normalized_shape = normalize_angle_and_shape(rot, shape)
                oriented_detection_box = OrientedDetectionBox.from_opencv(
                    center, normalized_shape, normalized_rot, class_name=class_name
                )
                detection_boxes.append(oriented_detection_box)
        return cls(detection_boxes)

    @classmethod
    def from_geodataframe(
        cls, gdf: gpd.GeoDataFrame, on_geometry: bool = False
    ) -> Self:
        """
        Instantiate  a GeoAnnotations object from a geodataframe.
        If on_geometry is set to True then we expect the geometry column of the geodataframe to be polygons
        and instantiate  coordinates from this.
        """

        def get_coords(geom: BaseGeometry) -> npt.NDArray[np.float64]:
            if geom.geom_type == "LineString":
                return np.array(geom.coords)
            if geom.geom_type == "Polygon":
                return np.array(geom.exterior.coords)
            raise ValueError(f"Geometry type is not Polygon ({geom.geom_type})")

        if not on_geometry:
            detection_boxes = [
                OrientedDetectionBox.from_dict(dict(info.to_dict()))
                for _, info in gdf.iterrows()
            ]
            return cls(detection_boxes)

        detection_boxes = []
        for i, info in gdf.iterrows():
            try:
                coords = get_coords(info.geometry)
                oriented_bb = convert_2d_coords_to_oriented_detection_box(
                    coords,
                    score=info.get("score", 1.0),
                    class_id=info.get("class_id", 0),
                    class_name=info.get("class_name", "N/A"),
                )
            except ValueError as e:
                raise ValueError(
                    f"Could not extract coordinates from geometry at row {i}"
                ) from e
            detection_boxes.append(oriented_bb)
        return cls(detection_boxes)

    def to_enclosing_boxes(self) -> "GeoAnnotations":
        """
        Returns a new instance of GeoAnnotations with enclosing bounding boxes.
        These boxes have null angle and surround the former oriented box.
        """
        detection_boxes = [box.enclosing_box() for box in self.detection_boxes]
        return GeoAnnotations(detection_boxes)

    def to_pascalvoc(self, size: AnnotationSize, *args, **kwargs) -> PascalVocXml:
        objs = [PascalVocObject.from_detection_box(bb) for bb in self.detection_boxes]
        return PascalVocXml(objs, size, *args, **kwargs)

    def to_geodataframe(self, geo_type="oriented", **kwargs) -> gpd.GeoDataFrame:
        """Returns a geodataframe with detection boxes information.

        Columns are : xmin, ymin, xmax, ymax, width, height, center_x, center_y, angle, score, class_id, class_name
        """
        records = [box.to_dict() for box in self.detection_boxes]
        df = pd.DataFrame.from_records(records)
        gdf = gpd.GeoDataFrame(df, **kwargs)
        gdf["geometry"] = self.compute_geometries(geo_type)
        return gdf

    def to_dxf(
        self,
        class2layer: Dict[str, str],
        layer2color: Dict[str, int],
        lineweight: int = 45,
    ) -> ezdxf.document.Drawing:
        doc = ezdxf.new()
        msp = doc.modelspace()

        for layer, color_value in layer2color.items():
            doc.layers.new(
                name=layer,
                dxfattribs={
                    "linetype": "CONTINUOUS",
                    "color": color_value,
                    "lineweight": lineweight,
                },
            )

        for obj in self.detection_boxes:
            coords = obj.to_quad()
            n_coord = len(coords)
            for i in range(n_coord):
                j = (i + 1) % n_coord
                msp.add_line(
                    coords[i],
                    coords[j],
                    dxfattribs={"layer": class2layer[obj.class_name]},
                )

        return doc

    def compute_geometries(self, geo_type: str) -> gpd.GeoSeries:
        """
        :param geo_type: A string following this convention:
            - 'center': will create a Point geometry at the center of the bounding box
            - 'oriented': will create a Polygon with the given angle if boxes are instances of ``OrientedDetectionBox``
        """
        if geo_type == "center":
            xs = [box.center[0] for box in self.detection_boxes]
            ys = [box.center[1] for box in self.detection_boxes]
            return gpd.GeoSeries(gpd.points_from_xy(xs, ys))
        elif geo_type == "oriented":
            geoms = []
            for box in self.detection_boxes:
                quad = box.to_quad()
                coords = [*quad, quad[0]]
                geoms.append(Polygon(coords))
            return gpd.GeoSeries(geoms)
        else:
            raise NotImplementedError

    def reset_angles(self, classes: Optional[List[str]] = None):
        """Force angles to be 0 for each classes given in parameter
        If no classes are given, then all objects will have their angle set to 0"""

        def _reset_obj_angle(box: OrientedDetectionBox):
            if classes is None or box.class_name in classes:
                box.angle = 0.0
            return box

        self.detection_boxes = list(map(_reset_obj_angle, self.detection_boxes))

    def reset_scales(self, classes: Dict[str, Tuple[Number, Number]]):
        """Will assign new scales to each class"""

        def _reset_obj_scale(box: OrientedDetectionBox):
            if box.class_name in classes.keys():
                new_shape = classes[box.class_name]
                box.set_shape(new_shape)
            return box

        self.detection_boxes = list(map(_reset_obj_scale, self.detection_boxes))

    def merge_overlapping_boxes(
        self,
        class_names: Optional[List[str]] = None,
        keep_highest: Optional[str] = "score",
    ) -> "GeoAnnotations":
        """This utility method is used to filter detections that have been done on a tiled dataset with overlapping
        parts on every tile. This induced an important number of detections for the same object.
        By sorting detections by the model score confidence and selecting only the surest detection from a cluster
        of jointly overlapping same class detections.

        :param class_names: List of classes to consider
        :param keep_highest: Method used to keep a detection box, either "score" or "area", to keep the
            highest score (i.e. area) when overlaps arise.
        """
        if len(self) == 0:
            logging.warning("Cannot merge overlapping boxes if non are present")
            return GeoAnnotations([])
        if keep_highest not in ["score", "area"]:
            raise ValueError("keep_highest is not set to 'score' nor 'area'")
        if not class_names:  # If no classes are given then all classes are considered
            class_names = self.classes

        detection_gdf = self.to_geodataframe("oriented")
        detection_gdf["area"] = detection_gdf["width"] * detection_gdf["height"]

        det_ids = []
        already_seen_ids = []
        for class_name in class_names:
            class_detection_gdf = detection_gdf.query(f"class_name == '{class_name}'")
            merged = gpd.sjoin(class_detection_gdf, class_detection_gdf, how="left")
            merged = merged.reset_index().rename(columns={"index": "index_left"})
            merged = merged.sort_values("score_left", ascending=False)

            for i_left, overlap_gdf in merged.groupby("index_left", sort=False):
                if (
                    i_left in det_ids
                ):  # If current detection have already been assigned to another, we do not treat it
                    already_seen_ids.extend(overlap_gdf.index_right)
                    continue

                already_seen_gdf = overlap_gdf.query(
                    "index_right.isin(@det_ids) or index_right.isin(@already_seen_ids)"
                )
                if already_seen_gdf.shape[0] > 0:
                    already_seen_ids.extend(already_seen_gdf.index_right)
                    continue

                max_score_det_id = overlap_gdf.loc[
                    overlap_gdf[f"{keep_highest}_right"].idxmax(), "index_right"
                ]
                det_ids.append(max_score_det_id)
                already_seen_ids.extend(overlap_gdf.index_right)

        detection_gdf = detection_gdf.loc[det_ids]
        return GeoAnnotations.from_geodataframe(detection_gdf)

    def filter(
        self, keeping_box_func: Callable[[DetectionBox], bool]
    ) -> "GeoAnnotations":
        return GeoAnnotations(
            [box for box in self.detection_boxes if keeping_box_func(box)]
        )

    def filter_by_score(self, min_score: float) -> "GeoAnnotations":
        return self.filter(lambda box: box.score >= min_score)

    def filter_by_class_name(self, classes: List[str]) -> "GeoAnnotations":
        return self.filter(lambda box: box.class_name in classes)

    def apply_class_mapping(self, class_mapping: Dict[str, str]) -> "GeoAnnotations":
        new_objects = [
            OrientedDetectionBox.from_bounding_box_and_angle(
                obj,
                obj.angle,
                obj.score,
                obj.class_id,
                class_mapping.get(obj.class_name, obj.class_name),
            )
            for obj in self.detection_boxes
        ]
        return GeoAnnotations(new_objects)

    @property
    def no_angles(self):
        return all(box.angle == 0 for box in self.detection_boxes)

    @property
    def classes(self) -> List[str]:
        return list({box.class_name for box in self.detection_boxes})

    def __len__(self):
        return len(self.detection_boxes)

    def __getitem__(self, key):
        return self.detection_boxes[key]

    def __contains__(self, item: BoundingBox):
        return item in self.detection_boxes
